import { Sprint, SprintSchema } from '../sprints/schemas/sprint.schema';

@Module({
  imports: [
    MongooseModule.forFeature([
      { name: Submission.name, schema: SubmissionSchema },
      { name: Sprint.name, schema: SprintSchema },
    ]),
  ],
