import { Injectable, BadRequestException, NotFoundException } from '@nestjs/common';
import { InjectModel } from '@nestjs/mongoose';
import { Model } from 'mongoose';
import { User, UserDocument, USER_ROLES } from './schemas/user.schema';
import { Team, TeamDocument } from '../teams/schemas/team.schema';
import { AuthService } from '../auth/auth.service';
import { UpdateUserDto } from './dto/update-user.dto';

@Injectable()
export class UsersService {
  constructor(
    @InjectModel(User.name) private readonly userModel: Model<UserDocument>,
    @InjectModel(Team.name) private readonly teamModel: Model<TeamDocument>,
    private readonly authService: AuthService,
  ) {}

  private toSafeUser(user: any) {
    return {
      id: String(user._id),
      username: user.username,
      name: user.name,
      firstName: user.firstName ?? '',
      lastName: user.lastName ?? '',
      email: user.email,
      role: user.role,
      isActive: user.isActive !== false,
      assignedTeams: Array.isArray(user.assignedTeams) ? user.assignedTeams : [],
      okta_id: user.okta_id ?? '',
      createdAt: user.createdAt,
      updatedAt: user.updatedAt,
    };
  }

  private normalizeRole(value: string): string {
    const role = String(value ?? '').trim();
    if (!Object.values(USER_ROLES).includes(role as any)) {
      throw new BadRequestException(
        `role must be one of: ${Object.values(USER_ROLES).join(', ')}`,
      );
    }
    return role;
  }

  private normalizeStatus(value?: string): string {
    const status = String(value ?? '').trim().toLowerCase();
    if (!status) return '';
    if (!['active', 'inactive'].includes(status)) {
      throw new BadRequestException("status must be 'active' or 'inactive'");
    }
    return status;
  }

  private async normalizeAssignedTeams(assignedTeams: string[], role: string) {
    if (role !== USER_ROLES.EDITOR) {
      return [];
    }

    const requested = [
      ...new Set(
        (Array.isArray(assignedTeams) ? assignedTeams : [])
          .map((team) => String(team ?? '').trim().toUpperCase())
          .filter(Boolean),
      ),
    ];

    if (requested.length === 0) {
      return [];
    }

    const existingTeams = await this.teamModel
      .find({ key: { $in: requested } }, { key: 1 })
      .lean();
    const existingKeys = new Set(existingTeams.map((team: any) => team.key));
    const invalid = requested.filter((key) => !existingKeys.has(key));
    if (invalid.length) {
      throw new BadRequestException(`Unknown team key(s): ${invalid.join(', ')}`);
    }

    return requested;
  }

  async listUsers(filters: Record<string, string> = {}) {
    await this.authService.ensureDefaultAdminUser();

    const query: Record<string, any> = {};
    const search = String(filters.search ?? '').trim();
    if (search) {
      query.$or = [
        { email: { $regex: search, $options: 'i' } },
        { username: { $regex: search, $options: 'i' } },
        { name: { $regex: search, $options: 'i' } },
      ];
    }

    if (filters.role) {
      query.role = this.normalizeRole(filters.role);
    }

    const status = this.normalizeStatus(filters.status);
    if (status === 'active') query.isActive = true;
    if (status === 'inactive') query.isActive = false;

    const users = await this.userModel.find(query).sort({ email: 1 }).lean();
    return users.map((user) => this.toSafeUser(user));
  }

  async updateUser(id: string, dto: UpdateUserDto) {
    await this.authService.ensureDefaultAdminUser();

    const user = await this.userModel.findById(id);
    if (!user) {
      throw new NotFoundException('User not found');
    }

    const nextRole =
      dto.role !== undefined ? this.normalizeRole(dto.role) : user.role;
    const nextIsActive =
      dto.isActive !== undefined ? Boolean(dto.isActive) : user.isActive !== false;
    const nextAssignedTeams = await this.normalizeAssignedTeams(
      dto.assignedTeams !== undefined ? dto.assignedTeams : user.assignedTeams,
      nextRole,
    );

    user.role = nextRole as any;
    user.isActive = nextIsActive;
    user.assignedTeams = nextAssignedTeams;
    await user.save();

    return this.toSafeUser(user);
  }
}

import { Test, TestingModule } from '@nestjs/testing';
import { INestApplication, ValidationPipe } from '@nestjs/common';
import * as request from 'supertest';
import { MongoMemoryServer } from 'mongodb-memory-server';
import { AppModule } from '../src/app.module';

describe('Auth + RBAC + Sprints (e2e)', () => {
  let app: INestApplication;
  let mongod: MongoMemoryServer;
  let adminToken = '';
  let viewerToken = '';
  let viewerUserId = '';

  beforeAll(async () => {
    mongod = await MongoMemoryServer.create();
    process.env.MONGO_URI = mongod.getUri();
    process.env.JWT_SECRET = 'e2e-secret';
    process.env.AUTH_STRICT_MODE = 'true';

    const moduleFixture: TestingModule = await Test.createTestingModule({
      imports: [AppModule],
    }).compile();

    app = moduleFixture.createNestApplication();
    app.setGlobalPrefix('api');
    app.useGlobalPipes(
      new ValidationPipe({
        whitelist: true,
        transform: true,
      }),
    );
    await app.init();
  });

  afterAll(async () => {
    await app.close();
    await mongod.stop();
  });

  it('signs in admin and returns JWT', async () => {
    const res = await request(app.getHttpServer())
      .post('/api/auth/signin')
      .send({
        email: 'mithunpramilak@etihad.ae',
        password: 'Admin@1234',
      })
      .expect(200);

    expect(res.body.ok).toBe(true);
    expect(res.body.token).toBeTruthy();
    expect(res.body.user.role).toBe('Admin');
    adminToken = res.body.token;
  });

  it('rejects non-etihad sign-in', async () => {
    const res = await request(app.getHttpServer())
      .post('/api/auth/signin')
      .send({
        email: 'someone@gmail.com',
        password: 'abc12345',
      })
      .expect(403);

    expect(res.body.error).toBeDefined();
  });

  it('creates viewer user and blocks viewer from admin sprint action', async () => {
    const signInRes = await request(app.getHttpServer())
      .post('/api/auth/signin')
      .send({
        email: 'viewer1@etihad.ae',
        password: 'Viewer@123',
      })
      .expect(200);

    viewerToken = signInRes.body.token;
    viewerUserId = signInRes.body.user.id;

    await request(app.getHttpServer())
      .post('/api/sprints')
      .set('Authorization', `Bearer ${viewerToken}`)
      .send({
        sprint: '99.1',
        pi: 99,
        start: '2099-01-01',
        end: '2099-01-14',
      })
      .expect(403);
  });

  it('allows admin to create sprint and list sprints', async () => {
    await request(app.getHttpServer())
      .post('/api/sprints')
      .set('Authorization', `Bearer ${adminToken}`)
      .send({
        sprint: '99.1',
        pi: 99,
        start: '2099-01-01',
        end: '2099-01-14',
      })
      .expect(201);

    const listRes = await request(app.getHttpServer())
      .get('/api/sprints')
      .set('Authorization', `Bearer ${adminToken}`)
      .expect(200);

    expect(Array.isArray(listRes.body)).toBe(true);
    expect(listRes.body.some((s: any) => s.sprint === '99.1')).toBe(true);
  });

  it('promotes user to editor and still blocks editor from admin-only sprint create', async () => {
    await request(app.getHttpServer())
      .put(`/api/users/${viewerUserId}`)
      .set('Authorization', `Bearer ${adminToken}`)
      .send({
        role: 'Editor',
        isActive: true,
        assignedTeams: [],
      })
      .expect(200);

    const editorSignInRes = await request(app.getHttpServer())
      .post('/api/auth/signin')
      .send({
        email: 'viewer1@etihad.ae',
        password: 'Viewer@123',
      })
      .expect(200);

    const editorToken = editorSignInRes.body.token;

    await request(app.getHttpServer())
      .post('/api/sprints')
      .set('Authorization', `Bearer ${editorToken}`)
      .send({
        sprint: '99.2',
        pi: 99,
        start: '2099-01-15',
        end: '2099-01-28',
      })
      .expect(403);
  });
});

